SET client_encoding = 'UTF8';
DROP TABLE IF EXISTS Asignacion CASCADE;
DROP TABLE IF EXISTS Vehiculo CASCADE;
DROP TABLE IF EXISTS Materia CASCADE;
DROP TABLE IF EXISTS Docente CASCADE;
DROP TABLE IF EXISTS Carrera CASCADE;
CREATE TABLE Carrera (carrera_id INT PRIMARY KEY, nombre VARCHAR(100), siglas VARCHAR(10));
CREATE TABLE Docente (docente_id SERIAL PRIMARY KEY, nombre VARCHAR(255) NOT NULL, grado VARCHAR(50), condicion VARCHAR(50), genero VARCHAR(50), domicilio TEXT, rfc VARCHAR(50), credencial_ine VARCHAR(100), estado_evaluacion VARCHAR(50) DEFAULT 'Pendiente');
CREATE TABLE Materia (materia_id SERIAL PRIMARY KEY, nombre VARCHAR(255) NOT NULL, carrera_id INT REFERENCES Carrera(carrera_id));
CREATE TABLE Vehiculo (vehiculo_id SERIAL PRIMARY KEY, docente_id INT REFERENCES Docente(docente_id), placas VARCHAR(20), marca VARCHAR(50), modelo VARCHAR(50));
CREATE TABLE Asignacion (asignacion_id SERIAL PRIMARY KEY, docente_id INT REFERENCES Docente(docente_id), materia_id INT REFERENCES Materia(materia_id), horas INT DEFAULT 0);
